INSERT INTO public.diet_threads (title, content, category_tag, nickname, like_count, comment_count, views, image) VALUES 
('마운자로 5mg 8주차, 누적 7.4kg 감량 후기 (용량 적응기 포함)', '2.5mg로 시작해 4주마다 증량했습니다. 첫 주는 메스꺼움이 있었지만 기름진 음식만 피하니 견딜 만했어요. 8주차 누적 7.4kg 빠졌고, 가장 큰 변화는 ''음식 생각이 머릿속에서 사라진'' 느낌입니다. 단백질과 물만 잘 챙기면 근손실은 크게 없었어요.', 'treatment', '마운자로러', 128, 34, 8421, 'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?auto=format&fit=crop&w=520&q=80'),
('위고비 vs 마운자로, 두 개 다 써본 솔직 비교', '위고비(세마글루타이드)를 4개월, 이후 마운자로(터제파타이드)로 바꿔 3개월째입니다. 식욕 억제는 마운자로가 체감상 더 강했고, 위고비는 메스꺼움이 더 오래갔어요. 다만 사람마다 반응이 달라서 처방받는 곳에서 충분히 상담받는 걸 추천합니다.', 'treatment', '둘다써봄', 96, 27, 6310, 'https://images.unsplash.com/photo-1576091160550-2173dba999ef?auto=format&fit=crop&w=520&q=80'),
('체지방률 31%에서 24%까지, 5개월 비포&애프터', '무리한 절식 대신 점심 탄수화물 양을 줄이고 주 3회 근력운동을 했습니다. 숫자보다 허리둘레 변화가 더 크게 느껴져요. 약과 병행하면서도 운동은 꼭 챙겼습니다.', 'review', '천천히빼자', 213, 41, 9844, 'https://images.unsplash.com/photo-1518611012118-696072aa579a?auto=format&fit=crop&w=520&q=80'),
('94kg → 71kg 비포&애프터 사진 인증합니다 (6개월)', '마운자로 + 식단 기록을 병행했습니다. 가장 효과 본 건 ''먹은 걸 전부 기록''한 거예요. 무의식적으로 먹던 간식이 눈에 보이니 자연스럽게 줄더라고요. 인바디 변화도 같이 올립니다.', 'review', '23키로뺀사람', 187, 52, 7720, 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?auto=format&fit=crop&w=520&q=80'),
('오늘 저녁 식단 인증, 닭가슴살 샐러드로 버텼어요', '야근 때문에 배달 생각이 굴뚝같았지만 준비해둔 샐러드로 마무리했습니다. 드레싱은 반만 넣으니 훨씬 낫네요. 위고비 맞고 나선 양도 자연스럽게 줄었어요.', 'meal', '샐러드장인', 64, 12, 2203, 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&w=520&q=80'),
('위고비 맞는 날 단백질 식단 (하루 120g 채우는 법)', '식욕이 줄다 보니 오히려 단백질이 부족해지기 쉬워요. 그릭요거트, 두부, 계란, 닭가슴살로 끼니당 30g씩 나눠 먹습니다. 적게 먹어도 영양은 챙겨야 근손실을 막을 수 있어요.', 'meal', '단백질사수', 71, 9, 1890, 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?auto=format&fit=crop&w=520&q=80'),
('삭센다 중단 후 요요가 걱정되는데 유지 방법 있을까요?', '중단 2주차부터 식욕이 올라오는 느낌입니다. 비슷한 경험 있으신 분들 유지 루틴 공유 부탁드려요. 천천히 감량할 걸 그랬나 후회도 됩니다.', 'side_effect', '유지중', 33, 18, 2788, 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?auto=format&fit=crop&w=520&q=80'),
('마운자로 메스꺼움/변비 부작용, 이렇게 버텼습니다', '증량 직후 3~4일이 가장 힘들었어요. 기름진 음식·과식을 피하고, 물을 평소보다 많이 마시고, 식이섬유(차전자피)를 챙기니 변비가 한결 나아졌습니다. 너무 심하면 증량을 미루는 것도 방법이에요.', 'side_effect', '부작용극복', 58, 23, 3410, 'https://images.unsplash.com/photo-1559757148-5c350d0d3c56?auto=format&fit=crop&w=520&q=80'),
('위고비 처방, 비대면으로 받아도 괜찮을까요?', '직장 때문에 병원 방문이 어려워 비대면 처방을 알아보고 있습니다. 정품 여부랑 배송, 가격대가 궁금한데 실제로 받아보신 분 후기 부탁드려요.', 'side_effect', '처방고민', 19, 15, 1506, 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?auto=format&fit=crop&w=520&q=80'),
('복부 지방흡입 상담 다녀왔는데 병원 고를 때 뭘 봐야 하나요?', '가격 차이가 커서 고민입니다. 후관리와 마취 방식, 압박복 관리까지 체크하면 될까요? 약으로 전체적으로 빼고 부분만 시술 고민 중입니다.', 'general', '라인고민', 24, 11, 1206, 'https://images.unsplash.com/photo-1579758629938-03607ccdbaba?auto=format&fit=crop&w=520&q=80'),
('간헐적 단식 16:8 + 위고비 병행, 시너지 있나요?', '공복 시간을 늘리면서 약 효과를 같이 보려는데, 저혈당 걱정도 됩니다. 두 가지 병행하시는 분들 컨디션 어떠신지 궁금해요.', 'general', '공복러', 27, 14, 1633, 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?auto=format&fit=crop&w=520&q=80'),
('정체기 3주째, 마운자로 용량 유지 vs 증량 고민', '5mg에서 체중이 2주 넘게 멈췄습니다. 운동량을 늘려야 할지, 증량을 해야 할지 고민이에요. 정체기 뚫은 경험담 공유해주시면 감사하겠습니다.', 'treatment', '정체기탈출', 41, 19, 2950, 'https://images.unsplash.com/photo-1434596922112-19c563067271?auto=format&fit=crop&w=520&q=80');